import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import { useNavigate, useLocation } from 'react-router-dom';
import Nav from './Nav';

const CustomerViewOrders = () => {
    const [orders, setOrders] = useState([]);
    const [message, setMessage] = useState('');
    const navigate = useNavigate();
    const customerId = sessionStorage.getItem("customerid");
    const location = useLocation();

    const fetchOrders = useCallback(async () => {
        setMessage('Loading your orders...');
        try {
            const response = await axios.post("http://localhost:3001/customer/vieworders", { customerId });

            if (Array.isArray(response.data) && response.data.length > 0) {
                const sortedOrders = response.data.sort((a, b) => new Date(b.orderDate) - new Date(a.orderDate));
                setOrders(sortedOrders);
                setMessage(''); // Clear loading message on success
            } else {
                setOrders([]);
                setMessage(response.data.message || 'You have no past orders.');
            }
        } catch (err) {
            console.error("Error fetching orders:", err);
            setOrders([]);
            setMessage("Could not fetch your orders. Please try again later.");
        }
    }, [customerId]);

    // This effect handles ONLY the post-payment redirect logic to clean the URL
    useEffect(() => {
        const params = new URLSearchParams(location.search);
        if (params.get('payment') === 'complete') {
            // Set a flag in sessionStorage that we can read in the other effect.
            sessionStorage.setItem('justPaid', 'true');
            // Clean the URL, which will trigger a re-render.
            navigate('/customer/vieworders', { replace: true });
        }
    }, [location.search, navigate]);

    // This effect fetches data, handling the post-payment case with a delay
    useEffect(() => {
        if (!customerId) {
            return; // The first effect will handle the redirect if needed.
        }
        const justPaid = sessionStorage.getItem('justPaid');
        if (justPaid === 'true') {
            // This block runs only after a payment redirect.
            sessionStorage.removeItem('justPaid'); // Clean up the flag immediately
            setMessage('Payment successful! Verifying status, please wait...');

            // Wait for a few seconds to give the backend webhook time to arrive and process.
            // Note: This is not 100% reliable. A better solution would be to poll the backend.
            const timer = setTimeout(fetchOrders, 3000);

            // Clean up the timer if the component unmounts before the timer fires.
            return () => clearTimeout(timer);
        } else {
            // This block runs on a normal page load (not after a payment).
            fetchOrders();
        }
    // This effect should not depend on location.search. It relies on the sessionStorage flag.
    }, [customerId, navigate, fetchOrders]);

    return (
        <div className="container">
            <Nav />
            <div className="row mt-3">
                <div className="col-12">
                    <h2 className="mb-4">Your Past Orders</h2>
                    {message && !message.startsWith('Loading') && (
                        <div className={`alert ${message.includes('successful') ? 'alert-success' : 'alert-info'}`} role="alert">
                            {message}
                        </div>
                    )}
                </div>
            </div>
            <div className="row g-3 mt-2">
                {orders.length > 0 ? orders.map(order => (
                    <div key={order._id} className="col-12">
                        <div className="card mb-3 shadow-sm">
                            <div className="card-header bg-light">
                                <div className="d-flex flex-column flex-md-row justify-content-between align-items-md-center">
                                    <div className="mb-2 mb-md-0"><strong>Order ID:</strong> {order._id}</div>
                                    <div className="mb-2 mb-md-0"><strong>Date:</strong> {new Date(order.orderDate).toLocaleDateString('en-GB', { day: '2-digit', month: '2-digit', year: 'numeric' })}</div>
                                    <div>
                                        <strong>Status:</strong>
                                        <span className={`badge ms-2 ${order.paymentStatus === 'Paid' ? 'bg-success' : 'bg-warning text-dark'}`}>
                                            {order.paymentStatus}
                                        </span>
                                    </div>
                                </div>
                            </div>
                            <div className="card-body">
                                <div className="row row-cols-1 g-3">
                                    {order.items.map(item => (
                                        <div className="col" key={item._id}>
                                            <div className="card h-100">
                                                <div className="row g-0">
                                                    <div className="col-md-4 d-flex align-items-center justify-content-center p-2">
                                                        <img src={item.productId?.link} className="img-fluid rounded object-fit-contain" alt={item.productId?.name} height={100} />
                                                    </div>
                                                    <div className="col-md-8">
                                                        <div className="card-body d-flex flex-column justify-content-center h-100">
                                                            <h6 className="card-title">{item.productId ? item.productId.name : 'Product not found'}</h6>
                                                            <p className="card-text mb-1"><small className="text-muted">Unit Price: ₹{item.productId ? item.productId.price.toFixed(2) : 'N/A'} | Quantity: {item.quantity}</small></p>
                                                            <p className="card-text"><strong>Subtotal: ₹{item.productId ? (item.productId.price * item.quantity).toFixed(2) : 'N/A'}</strong></p>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                            <div className="card-footer text-end bg-light">
                                <h5 className="mb-0">Order Total: <strong>₹{order.totalAmount.toFixed(2)}</strong></h5>
                            </div>
                        </div>
                    </div>
                )) : (
                        !message && (
                            <div className="col-12 text-center mt-3">
                                <p>You have no past orders.</p>
                            </div>
                        )
                    )}
            </div>
        </div>
    );
};

export default CustomerViewOrders
